import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Goose — Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/goose/benchmarks.md","filePath":"research/agents/goose/benchmarks.md"}'),n={name:"research/agents/goose/benchmarks.md"};function i(s,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="goose-—-benchmarks" tabindex="-1">Goose — Benchmarks <a class="header-anchor" href="#goose-—-benchmarks" aria-label="Permalink to &quot;Goose — Benchmarks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Goose has been evaluated on Terminal-Bench, a benchmark focused on terminal-based coding agent performance. It has appeared across both Terminal-Bench 1.0 and 2.0 leaderboards.</p><p>Note: Goose&#39;s benchmark presence is more limited compared to agents like Claude Code or Codex CLI, partly because it&#39;s a newer entrant and partly because its multi-provider architecture means performance varies significantly by model choice.</p><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h2><p>Terminal-Bench 2.0 is an updated benchmark with harder tasks and more rigorous evaluation.</p><h3 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Configuration</th><th>Rank</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>Goose + Claude Opus 4.5</td><td>#44</td><td>54.3%</td><td>Best Goose configuration on TB2.0</td></tr><tr><td>Goose + Claude Sonnet 4.5</td><td>#61</td><td>43.1%</td><td>More cost-effective option</td></tr></tbody></table><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>For comparison on Terminal-Bench 2.0:</p><ul><li>Top agents score in the 70-80%+ range</li><li>Claude Code (native) typically ranks in the top 5-10</li><li>Goose&#39;s mid-table positioning reflects its generalist architecture — it&#39;s optimized for extensibility rather than raw benchmark performance</li></ul><h3 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h3><p>The ~11% gap between Opus 4.5 and Sonnet 4.5 configurations suggests Goose benefits significantly from stronger reasoning models. This is consistent with its architecture: the agent loop handles tool dispatch and context management, but the quality of planning and code generation depends entirely on the underlying model.</p><h2 id="terminal-bench-1-0" tabindex="-1">Terminal-Bench 1.0 <a class="header-anchor" href="#terminal-bench-1-0" aria-label="Permalink to &quot;Terminal-Bench 1.0&quot;">​</a></h2><p>Terminal-Bench 1.0 was the original benchmark with a broader set of terminal-based tasks.</p><h3 id="results-1" tabindex="-1">Results <a class="header-anchor" href="#results-1" aria-label="Permalink to &quot;Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Configuration</th><th>Rank</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>Goose + claude-opus-4</td><td>#17</td><td>45.3%</td><td>Strong showing on TB1.0</td></tr></tbody></table><h3 id="context-1" tabindex="-1">Context <a class="header-anchor" href="#context-1" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Rank #17 on Terminal-Bench 1.0 places Goose in the competitive middle tier. The benchmark measures end-to-end task completion in terminal environments, which aligns well with Goose&#39;s developer tool extension (shell, file editing, tree).</p><h2 id="swe-bench" tabindex="-1">SWE-bench <a class="header-anchor" href="#swe-bench" aria-label="Permalink to &quot;SWE-bench&quot;">​</a></h2><p>Goose has not been widely reported on SWE-bench as of this research. This may be because:</p><ul><li>SWE-bench focuses on repository-level bug fixing, which requires deep code understanding</li><li>Goose&#39;s strength is in extensibility and automation workflows rather than concentrated code reasoning</li><li>The multi-provider architecture makes it harder to submit a single canonical result</li></ul><h2 id="performance-factors" tabindex="-1">Performance Factors <a class="header-anchor" href="#performance-factors" aria-label="Permalink to &quot;Performance Factors&quot;">​</a></h2><h3 id="model-dependency" tabindex="-1">Model Dependency <a class="header-anchor" href="#model-dependency" aria-label="Permalink to &quot;Model Dependency&quot;">​</a></h3><p>Goose&#39;s performance is heavily model-dependent since it&#39;s provider-agnostic:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Expected Relative Performance</th></tr></thead><tbody><tr><td>Claude Opus 4 / 4.5</td><td>Highest (best tool-calling)</td></tr><tr><td>Claude Sonnet 4 / 4.5</td><td>Strong (recommended default)</td></tr><tr><td>GPT-4o</td><td>Good</td></tr><tr><td>Gemini 2.5 Pro</td><td>Good</td></tr><tr><td>Local models (Ollama)</td><td>Lower (toolshim adds overhead)</td></tr></tbody></table><p>The docs note: &quot;goose relies heavily on tool calling capabilities and currently works best with Claude 4 models.&quot;</p><h3 id="architectural-overhead" tabindex="-1">Architectural Overhead <a class="header-anchor" href="#architectural-overhead" aria-label="Permalink to &quot;Architectural Overhead&quot;">​</a></h3><p>Goose&#39;s extensibility comes with overhead that affects benchmark performance:</p><ol><li><strong>MCP serialization</strong>: Even built-in tools go through MCP protocol serialization</li><li><strong>Extension loading</strong>: Multiple MCP server processes start at session beginning</li><li><strong>Security inspection</strong>: Every tool call passes through 4 inspectors</li><li><strong>Context management</strong>: Background summarization and MOIM injection add tokens</li><li><strong>Tool namespacing</strong>: <code>extension__tool</code> prefixes consume tokens in the tool list</li></ol><h3 id="strengths-for-benchmarks" tabindex="-1">Strengths for Benchmarks <a class="header-anchor" href="#strengths-for-benchmarks" aria-label="Permalink to &quot;Strengths for Benchmarks&quot;">​</a></h3><ol><li><strong>Robust error recovery</strong>: Auto-compaction and retry logic handle long tasks gracefully</li><li><strong>Broad tool access</strong>: Extensions can provide specialized tools for specific task types</li><li><strong>Recipe mode</strong>: Automated retry with success criteria helps complete challenging tasks</li><li><strong>Max turns = 1000</strong>: Very high iteration limit allows persistent problem-solving</li></ol><h3 id="weaknesses-for-benchmarks" tabindex="-1">Weaknesses for Benchmarks <a class="header-anchor" href="#weaknesses-for-benchmarks" aria-label="Permalink to &quot;Weaknesses for Benchmarks&quot;">​</a></h3><ol><li><strong>Generalist design</strong>: Not optimized for any single benchmark&#39;s task distribution</li><li><strong>Extension overhead</strong>: Multiple MCP servers add latency per turn</li><li><strong>Token overhead</strong>: Tool namespacing, MOIM injection, and system prompt instrumentation use tokens</li><li><strong>No specialized reasoning</strong>: Unlike agents with built-in code analysis or search, Goose delegates everything to extensions</li></ol><h2 id="benchmark-methodology-notes" tabindex="-1">Benchmark Methodology Notes <a class="header-anchor" href="#benchmark-methodology-notes" aria-label="Permalink to &quot;Benchmark Methodology Notes&quot;">​</a></h2><h3 id="terminal-bench-specifics" tabindex="-1">Terminal-Bench Specifics <a class="header-anchor" href="#terminal-bench-specifics" aria-label="Permalink to &quot;Terminal-Bench Specifics&quot;">​</a></h3><p>Terminal-Bench evaluates agents on their ability to:</p><ul><li>Execute multi-step terminal commands</li><li>Navigate file systems</li><li>Edit code and configuration files</li><li>Debug and fix issues</li><li>Install dependencies and run tests</li></ul><p>Goose&#39;s Developer extension (shell, edit, write, tree) is the primary tool set for these tasks. The benchmark score reflects the combined quality of:</p><ol><li>The underlying LLM&#39;s reasoning and planning</li><li>Goose&#39;s tool dispatch efficiency</li><li>Error recovery and retry behavior</li><li>Context management over long task sequences</li></ol><h3 id="reproducibility" tabindex="-1">Reproducibility <a class="header-anchor" href="#reproducibility" aria-label="Permalink to &quot;Reproducibility&quot;">​</a></h3><p>Running Goose benchmarks requires specifying:</p><ul><li>Exact model version (e.g., <code>claude-opus-4-20250514</code>)</li><li>Extension configuration (which extensions are enabled)</li><li>Permission mode (autonomous for benchmarks)</li><li>Context limit and compaction settings</li></ul><h2 id="summary-table" tabindex="-1">Summary Table <a class="header-anchor" href="#summary-table" aria-label="Permalink to &quot;Summary Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Version</th><th>Model</th><th>Rank</th><th>Score</th></tr></thead><tbody><tr><td>Terminal-Bench</td><td>2.0</td><td>Claude Opus 4.5</td><td>#44</td><td>54.3%</td></tr><tr><td>Terminal-Bench</td><td>2.0</td><td>Claude Sonnet 4.5</td><td>#61</td><td>43.1%</td></tr><tr><td>Terminal-Bench</td><td>1.0</td><td>claude-opus-4</td><td>#17</td><td>45.3%</td></tr></tbody></table><h2 id="verdict" tabindex="-1">Verdict <a class="header-anchor" href="#verdict" aria-label="Permalink to &quot;Verdict&quot;">​</a></h2><p>Goose performs respectably on benchmarks but is not a top-tier performer. Its architecture prioritizes extensibility, provider flexibility, and enterprise safety over raw benchmark scores. For organizations that need a configurable, secure, MCP-native agent that works with their chosen LLM provider, Goose&#39;s moderate benchmark performance is an acceptable trade-off. For pure coding performance, dedicated agents like Claude Code with their tighter model integration tend to perform better.</p>',47)])])}const b=t(n,[["render",i]]);export{u as __pageData,b as default};
